mapper.select:
SELECT r.id as resourceId, r.name, r.description, r.file_type as fileType, r.file_size as fileSize, r.download_count as downloadCount, r.create_time as createTime, s.name as subjectName, g.name as gradeName FROM resource r LEFT JOIN subject s ON r.subject_id = s.id LEFT JOIN grade g ON r.grade_id = g.id WHERE r.is_deleted = 0
AND r.subject_id = #{subjectId}
AND r.grade_id = #{gradeId}
AND (r.name LIKE CONCAT('%', #{keyword}, '%') OR r.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.create_time DESC
